### Hop 1: `start_node --R1--> {h1_i}`

```rust
fn hop1(start: &BinaryAtom, r1: &Relation, codebook: &AtomMemory) -> Frontier {
    // === STEP 1a: Seed frontier (XOR→COUNT, free) ===
    let mut c0 = CountCentroid::zero();
    for j in start.iter_set_bits() { c0.counts[j] = 1; }
    c0.n_items = 1;
    c0.l1_norm = 64;

    let seed_bundle = FrontierBundle {
        centroids: std::array::from_fn(|i| if i == 0 { c0.clone() } else { CountCentroid::zero() }),
        member_ids: vec![0],
        assign: vec![0],
    };

    let mut frontier = Frontier {
        bundle: seed_bundle,
        atoms: vec![(start.clone(), 1.0)],
    };

    // === STEP 1b: Lookup triples (start, R1, ?) in CompositeMemory ===
    // For hop 1, frontier size = 1, so we use XOR exact path.
    let composite_key = start.xor(&r1.mask);  // BinaryAtom XOR BinaryAtom
    let targets: Vec<BinaryAtom> = COMPOSITE_MEMORY.lookup(&composite_key);

    // === STEP 1c: Collapse to discrete atoms (COUNT→XOR, but trivial here) ===
    // Since we used XOR path, no collapse needed. Just record results.
    frontier.atoms = targets.into_iter().map(|t| (t, 1.0)).collect();

    // === STEP 1d: Re-fold into bundle for hop 2 (XOR→COUNT) ===
    frontier.fold_into_bundle();

    frontier
}
```

**State after Hop 1:**
- `frontier.atoms`: `Vec<(BinaryAtom, f32)>` with `k₁` discrete atoms (typical: 5-20)
- `frontier.bundle`: `FrontierBundle` with `k₁` items folded into M=8 centroids
- **SNR:** N=1, m=1, so SNR = √(16384·8 / 4·1) = √32768 ≈ 181. Trivially clean.

