        let next_atoms = frontier.collapse_from_bundle(r2, codebook);
        let mut next_frontier = Frontier {
            bundle: FrontierBundle::empty(),
            atoms: next_atoms,
        };
        next_frontier.fold_into_bundle();
        next_frontier
    }
}
