## 5. The Routing Decision (Exact Threshold)

```rust
const XOR_PATH_THRESHOLD: usize = 40;  // from Debate C: ~26 rules/shard before interference
const COUNT_PATH_SNR_FLOOR: f32 = 5.0; // 5σ for clean recovery

fn route(frontier_size: usize, expected_multiplicity: usize) -> PathChoice {
    if frontier_size < XOR_PATH_THRESHOLD {
        PathChoice::XOR
    } else {
        // Predict SNR for count path
        let predicted_snr = (expected_multiplicity as f32) 
            * (16384.0 * 8.0 / (4.0 * frontier_size as f32)).sqrt();
        if predicted_snr >= COUNT_PATH_SNR_FLOOR {
            PathChoice::COUNT
        } else {
            // SNR too low. Options: (a) prune frontier to top-40 and use XOR,
            // (b) accept lossy count path, (c) abort traversal.
            PathChoice::PRUNE_AND_XOR
        }
    }
}

enum PathChoice {
    XOR,           // exact, no SNR loss
    COUNT,         // statistical, SNR-gated
    PRUNE_AND_XOR, // truncate frontier to top-40 by score, then XOR
}
